export const localizedPages: LocalizedPage[] = [
  { lang:'de', slug:'erscheinungsdatum', englishPath:'/release-date/', title:'Control Resonant Erscheinungsdatum: Release und Early Access', description:'Control Resonant erscheint am 24. September 2026. Alle bestätigten Angaben zu Plattformen, Early Access und Mac-Version.', label:'Veröffentlichung', answer:'Control Resonant erscheint weltweit am 24. September 2026 für PS5, Xbox Series X|S und PC. Die Digital Deluxe Edition auf PS5 gewährt laut PlayStation 48 Stunden früheren Zugang ab dem 22. September. Eine Mac-Version ist für später im Jahr 2026 angekündigt.', sections:[
    {heading:'Der bestätigte Termin',paragraphs:['Remedy hat den 24. September 2026 als weltweiten Veröffentlichungstermin genannt. Auf dem PC wird das Spiel über Steam und den Epic Games Store angeboten; GeForce NOW soll zum Start unterstützt werden. Für macOS nennt Remedy bislang nur ein Zeitfenster später im Jahr 2026 und noch keinen konkreten Tag.','Der Termin ersetzt frühere allgemeine Angaben wie „2026“. Wir behandeln nur datierte Aussagen des Studios oder der Plattformbetreiber als bestätigt. Händlerangaben und nicht verlinkte Countdown-Seiten sind keine belastbaren Quellen.']},
    {heading:'Early Access und Editionen',paragraphs:['PlayStation bewirbt für die digitale Deluxe Edition einen 48-stündigen Early Access. Daraus ergibt sich auf PS5 der 22. September 2026, sofern sich das Angebot regional nicht ändert. Für andere Plattformen sollte man die jeweilige Store-Seite prüfen, weil Editionen und Freischaltzeiten voneinander abweichen können.','Ein Preload-Termin und die genaue Uhrzeit der weltweiten Freischaltung wurden noch nicht einheitlich bestätigt. Wir ergänzen diese Seite erst, wenn Remedy, Steam, Xbox oder PlayStation entsprechende Angaben veröffentlichen.']},
    {heading:'Was vor dem Start noch offen ist',paragraphs:['Offen sind unter anderem regionale Freischaltzeiten, der endgültige Mac-Termin und mögliche physische Ausgaben. Auch eine Verschiebung ist bei einem noch unveröffentlichten Spiel grundsätzlich möglich. Maßgeblich bleiben die offiziellen Store-Einträge und Remedys Mitteilungen.']}
  ], sources:sources([{label:'PlayStation Store',url:ps},{label:'Steam',url:steam}]) },
  { lang:'de', slug:'systemanforderungen', englishPath:'/guides/system-requirements/', title:'Control Resonant Systemanforderungen für PC', description:'Offizielle minimale und empfohlene PC-Systemanforderungen für Control Resonant: CPU, GPU, RAM, Speicher und Betriebssystem.', label:'PC-Leistung', answer:'Die Steam-Seite nennt Windows 10/11 (64 Bit), 16 GB RAM und 100 GB Speicherplatz. Minimal werden ein Intel Core i5-8500 oder AMD-Pendant sowie GTX 1070 beziehungsweise RX 5600 XT mit 6 GB genannt; empfohlen sind Ryzen 7 3700X oder Intel-Pendant und RTX 3070 beziehungsweise RX 6700 XT mit 8 GB.', sections:[
    {heading:'Minimale Konfiguration',paragraphs:['Die Mindestangaben beschreiben die schwächste offiziell unterstützte PC-Klasse, nicht automatisch eine garantierte Auflösung oder Bildrate. Steam nennt einen Core i5-8500 oder einen vergleichbaren AMD-Prozessor, 16 GB Arbeitsspeicher und eine GeForce GTX 1070 oder Radeon RX 5600 XT mit 6 GB Grafikspeicher.','Zusätzlich sind ein 64-Bit-Windows 10 oder Windows 11 und 100 GB freier Speicher erforderlich. Da keine Zielwerte für Grafikprofil, Auflösung und FPS angegeben werden, sollte diese Liste als Kompatibilitätsgrenze und nicht als Leistungsversprechen gelesen werden.']},
    {heading:'Empfohlene Konfiguration',paragraphs:['Für die empfohlene Stufe führt Steam einen Ryzen 7 3700X oder ein Intel-Pendant sowie eine RTX 3070 oder RX 6700 XT mit 8 GB VRAM auf. Arbeitsspeicher und belegter Speicher bleiben bei 16 GB beziehungsweise 100 GB.','Ob Raytracing, Upscaling oder Frame Generation in diesen Profilen eingerechnet sind, ist derzeit nicht erläutert. Wer einen neuen PC plant, sollte vor dem Kauf auf technische Hinweise von Remedy und aktualisierte Store-Daten warten.']},
    {heading:'So ordnest du deinen PC ein',paragraphs:['Vergleiche zuerst Grafikspeicher und GPU-Klasse, danach Prozessor und RAM. Ein einzelnes stärkeres Bauteil gleicht eine klare Unterschreitung bei VRAM oder Arbeitsspeicher nicht zuverlässig aus. Notebook-GPUs tragen oft ähnliche Namen wie Desktop-Modelle, können aber deutlich langsamer sein.']}
  ], sources:[{label:'Steam – offizielle Systemanforderungen',url:steam}] },
  { lang:'de', slug:'plattformen', englishPath:'/guides/platforms-and-performance/', title:'Control Resonant Plattformen: PS5, Xbox, PC und Mac', description:'Bestätigte Plattformen für Control Resonant sowie der aktuelle Stand zu Last-Gen, GeForce NOW und Leistung.', label:'Plattformen', answer:'Bestätigt sind PlayStation 5, Xbox Series X|S und PC zum 24. September 2026. GeForce NOW soll das PC-Spiel ab Veröffentlichung streamen. Eine Mac-Version folgt später 2026; PS4, Xbox One und Nintendo Switch sind nicht angekündigt.', sections:[
    {heading:'Plattformen zum Start',paragraphs:['Remedys offizielle Veröffentlichung nennt PS5, Xbox Series X|S sowie PC über Steam und Epic Games Store. Damit ist Resonant ein Spiel für die aktuelle Konsolengeneration. Eine Fassung für PS4 oder Xbox One ist nicht angekündigt.','GeForce NOW ist als Cloud-Option zum Launch genannt. Dafür wird weiterhin eine unterstützte PC-Lizenz und ein passendes GeForce-NOW-Abo benötigt; der Streaming-Dienst ist keine eigene Konsolenversion.']},
    {heading:'Mac und nicht bestätigte Systeme',paragraphs:['Die macOS-Version besitzt noch kein genaues Datum, sondern lediglich das Fenster „später 2026“. Welche Mac-Modelle und Apple-Chips unterstützt werden, hat Remedy noch nicht spezifiziert.','Eine Switch- oder mögliche Nachfolger-Version wurde nicht offiziell vorgestellt. Ohne Herstellerankündigung führen wir solche Plattformen nicht als geplant auf. Das verhindert, dass Wunschlisten oder Händler-Platzhalter mit bestätigten Fassungen verwechselt werden.']},
    {heading:'Auflösung und Bildrate',paragraphs:['Offizielle Performance-Modi für PS5 und Xbox Series X|S sind noch nicht vollständig dokumentiert. Aussagen zu 60 FPS, Raytracing oder Series-S-Abstrichen wären deshalb derzeit Spekulation. Diese Seite wird nach technischen Angaben der Plattformbetreiber aktualisiert.']}
  ], sources:sources([{label:'Steam',url:steam}]) },
  { lang:'de', slug:'kampfsystem-und-builds', englishPath:'/guides/combat-and-build-systems-explained/', title:'Control Resonant Kampfsystem und Builds erklärt', description:'So funktionieren Nahkampf, Aberrant-Waffenformen, Instinct und das Build-System The Gap in Control Resonant.', label:'Kampf & Builds', answer:'Control Resonant ist ein nahkampforientiertes Action-RPG. Dylan nutzt die formwandelnde Waffe Aberrant, paranatürliche Instinct-Fähigkeiten und das Build-System The Gap. Waffenformen, Mods und Kräfte sollen unterschiedliche Spielstile ermöglichen.', sections:[
    {heading:'Aberrant statt Service Weapon',paragraphs:['Aberrant kann sich in mehrere Nahkampfwerkzeuge verwandeln. Bestätigt sind Formen mit unterschiedlichen Reichweiten und Aufgaben, sodass Positionierung, Ausweichen und das Wechseln der Form wichtiger werden als dauerhaftes Schießen.','Der Kampf bleibt übernatürlich: Dylan kombiniert Waffenangriffe mit Instinct-Kräften. Die Entwickler beschreiben ein System, in dem Angriffe, Bewegungen und Fähigkeiten ineinandergreifen. Exakte Schadenswerte können sich vor Release noch ändern.']},
    {heading:'Buildcrafting in The Gap',paragraphs:['The Gap ist der zentrale Raum für Charakterentwicklung und Builds. Spieler ordnen freigeschaltete Elemente so an, dass Modifikatoren und Fähigkeiten zusammenwirken. Der offizielle Deep Dive betont Wahlfreiheit und deutlich unterschiedliche Ausrichtungen.','Sinnvoll ist es, einen Build um eine klare Aufgabe zu planen: Kontrolle von Gruppen, hoher Schaden gegen einzelne Ziele oder defensive Stabilität. Vor Veröffentlichung gibt es jedoch keine verlässliche Rangliste; Bezeichnungen und Balance aus Vorschauen sind vorläufig.']},
    {heading:'Was wir noch nicht seriös bewerten können',paragraphs:['Ohne finale Version lassen sich keine „besten Builds“ belegen. Wir trennen deshalb bestätigte Mechaniken von späteren Empfehlungen. Nach dem Launch werden Werte im Spiel getestet und Änderungen mit Versionsstand dokumentiert.']}
  ], sources:[{label:'PlayStation Blog – Combat Deep Dive',url:combat}] },
  { lang:'de', slug:'new-game-plus', englishPath:'/guides/new-game-plus/', title:'Control Resonant New Game Plus: bestätigte Details', description:'Alle offiziellen Informationen zu New Game Plus in Control Resonant, Fortschritt, Veränderungen und Freischaltung.', label:'Spielmodi', answer:'New Game Plus übernimmt Aberrant-Upgrades, Gesundheit, Kampffähigkeits-Ressource, Fähigkeiten, Talente und Artefakte. Fortbewegungsfähigkeiten werden wegen ihrer Bindung an den Storyfortschritt zurückgesetzt.', sections:[
    {heading:'Was offiziell bestätigt ist',paragraphs:['Remedy hat New Game Plus bereits vor der Veröffentlichung vorgestellt. Der Modus soll die Kampagne nach einem ersten Abschluss neu rahmen und zusätzliche Überraschungen enthalten. Damit ist er ein geplanter Bestandteil des Spiels und kein bloßes Gerücht.','Bestätigt übernommen werden Aberrant-Upgrades, Gesundheit, Combat-Ability-Ressource, freigeschaltete Kampffähigkeiten, Talente und Artefakte. Fortbewegungsfähigkeiten bleiben dagegen an die Story gebunden.']},
    {heading:'Fortschritt und Freischaltung',paragraphs:['Typischerweise setzt New Game Plus einen Kampagnenabschluss voraus; für Resonant sollte diese Bedingung aber erst als endgültig gelten, wenn Remedy das Menü und den Ablauf dokumentiert. Ebenso offen ist, ob mehrere NG+-Zyklen möglich sind.','Spieler sollten vor dem Finale einen manuellen Spielstand behalten, sofern das Speichersystem dies erlaubt. Das ist eine vorsichtige Empfehlung, keine bestätigte Pflicht. Nach Release ergänzen wir einen Schritt-für-Schritt-Ablauf.']},
    {heading:'Warum der Modus wichtig ist',paragraphs:['Ein Build-lastiges Action-RPG profitiert von stärkeren Gegnern und neuen Situationen, weil vollständig entwickelte Kombinationen sonst nur kurz genutzt werden. Entscheidend wird sein, ob neue Inhalte und Balance den zweiten Lauf wirklich verändern.']}
  ], sources:[{label:'PlayStation Blog – New Game Plus',url:ngp}] },
  { lang:'de', slug:'charaktere-und-story', englishPath:'/guides/characters-and-story/', title:'Control Resonant Charaktere und Story: Dylan Faden', description:'Ein spoilerarmer Überblick über Dylan Faden, Jesse, Manhattan und die Ausgangslage von Control Resonant.', label:'Story', answer:'Dylan Faden ist der spielbare Hauptcharakter von Control Resonant. Jahre nach Control gerät Manhattan durch eine paranatürliche Krise aus den Fugen. Jesse Faden bleibt für die Geschichte wichtig, doch Resonant soll als eigenständiger Einstieg funktionieren.', sections:[
    {heading:'Dylan im Mittelpunkt',paragraphs:['Im ersten Control war Dylan eng mit dem Hiss und den Experimenten des Federal Bureau of Control verbunden. Resonant macht ihn zur spielbaren Figur und untersucht, wie er mit seinen Kräften, seiner Vergangenheit und der Beziehung zu Jesse umgeht.','Offizielle Texte stellen ihn nicht als fertigen Helden dar. Seine instabilen Fähigkeiten und die neue Waffe Aberrant bilden sowohl den spielerischen als auch den persönlichen Kern der Geschichte.']},
    {heading:'Manhattan als Schauplatz',paragraphs:['Die Krise reicht nun über das Oldest House hinaus. Manhattan ist durch paranatürliche Ereignisse verzerrt, und Dylan bewegt sich durch eine größere, verbundene Umgebung. Das bedeutet nicht automatisch eine klassische Open World mit beliebig abhakbaren Symbolen.','Remedy beschreibt ein eigenständiges Abenteuer. Neue Spieler sollen der zentralen Handlung folgen können, während Kenner des ersten Spiels zusätzliche Zusammenhänge erkennen.']},
    {heading:'Spoiler und offene Fragen',paragraphs:['Wir nennen hier nur Material aus offiziellen Trailern und Beschreibungen. Jesses genaue Rolle, der Zustand des FBC und die Identität zentraler Gegner bleiben bewusst offen. Story-Leaks und unbestätigte Zusammenfassungen werden nicht als Fakten übernommen.']}
  ], sources:sources([{label:'PlayStation Blog – Story und Termin',url:story}]) },
  { lang:'de', slug:'sprachen', englishPath:'/guides/language-support/', title:'Control Resonant Sprachen: Deutsch, Audio und Untertitel', description:'Die offizielle Sprachunterstützung von Control Resonant mit deutscher Sprachausgabe, Oberfläche und Untertiteln.', label:'Sprachen', answer:'Deutsch wird laut offizieller Steam-Sprachmatrix vollständig unterstützt: Oberfläche, Untertitel und Sprachausgabe. Insgesamt sind 15 Sprachen für Oberfläche und Untertitel gelistet; neun davon besitzen vollständige Audioausgabe.', sections:[
    {heading:'Deutsche Unterstützung',paragraphs:['Steam setzt für Deutsch Häkchen bei Oberfläche, vollständiger Audioausgabe und Untertiteln. Deutsche Spieler können das Spiel daher nach aktuellem Stand komplett lokalisiert spielen. Ob alle Eigennamen übersetzt oder bewusst beibehalten werden, zeigt erst die finale Fassung.','Die Sprachmatrix ist eine offizielle Store-Angabe, kann aber bis zur Veröffentlichung aktualisiert werden. Wir empfehlen, kurz vor dem Kauf erneut die Store-Seite der gewünschten Plattform zu prüfen.']},
    {heading:'Alle gelisteten Sprachen',paragraphs:['Für Oberfläche und Untertitel sind Englisch, Französisch, Italienisch, Deutsch, Spanisch aus Spanien, Japanisch, Koreanisch, Polnisch, Portugiesisch aus Brasilien, Russisch, vereinfachtes Chinesisch, traditionelles Chinesisch, Ukrainisch, Spanisch aus Lateinamerika und Arabisch aufgeführt.','Vollständige Audioausgabe ist für Englisch, Französisch, Italienisch, Deutsch, Spanisch aus Spanien, Japanisch, brasilianisches Portugiesisch, vereinfachtes Chinesisch und Ukrainisch markiert. Koreanisch, Polnisch, Russisch, traditionelles Chinesisch, lateinamerikanisches Spanisch und Arabisch sind derzeit ohne Vollvertonung gelistet.']},
    {heading:'Plattformunterschiede beachten',paragraphs:['Steam dokumentiert die PC-Fassung. Konsolen-Downloads können Sprachpakete, Regionseinstellungen oder abweichende Store-Hinweise verwenden. Für PS5 und Xbox gilt deshalb immer auch der regionale Produkteintrag als maßgeblich.']}
  ], sources:[{label:'Steam – Sprachmatrix',url:steam}] },
  { lang:'de', slug:'open-world', englishPath:'/guides/is-control-resonant-open-world/', title:'Ist Control Resonant Open World?', description:'Was Remedy über die größere Manhattan-Spielwelt sagt und warum Control Resonant nicht einfach eine klassische Open World ist.', label:'Spielwelt', answer:'Control Resonant spielt in einer größeren, verbundenen Version von Manhattan, wird offiziell aber nicht schlicht als klassische Open World vermarktet. Am treffendsten ist derzeit: eine offene, erkundbare Action-RPG-Welt mit geführter Story und Metroidvania-Elementen.', sections:[
    {heading:'Was „offener“ konkret bedeutet',paragraphs:['Im Vergleich zu den abgeschlossenen Sektoren des Oldest House weitet Resonant den Maßstab deutlich aus. Dylan kann Manhattan erkunden, neue Wege erschließen und in bereits bekannte Bereiche zurückkehren.','Offene Wege sind nicht dasselbe wie eine vollständig freie Sandbox. Remedy legt weiterhin Wert auf inszenierte Missionen, räumliche Rätsel und kontrolliertes Storytelling. Deshalb vermeiden wir die pauschale Behauptung, es handle sich um eine typische Ubisoft-artige Kartenstruktur.']},
    {heading:'Erkundung und Fortschritt',paragraphs:['Neue Fähigkeiten dürften Zugänge und Bewegungsmöglichkeiten verändern. Offizielle Darstellungen zeigen eine zusammenhängendere Stadt, erklären aber noch nicht jedes Schnellreise-, Bezirks- oder Nebenmissionssystem.','Vor Release lässt sich auch die tatsächliche Kartengröße nicht seriös vergleichen. Trailer-Schnitte vermitteln keine zuverlässigen Entfernungen oder Spielzeiten.']},
    {heading:'Die präziseste Einordnung',paragraphs:['Wer eine reine lineare Kampagne erwartet, bekommt offenbar mehr Freiheit; wer eine grenzenlose Sandbox erwartet, sollte vorsichtiger sein. Nach Veröffentlichung prüfen wir Kartenstruktur, Rückwege, optionale Gebiete und Missionsfreiheit anhand der finalen Version.']}
  ], sources:sources([{label:'PlayStation Blog',url:story}]) },
  { lang:'de', slug:'barrierefreiheit', englishPath:'/guides/accessibility-options/', title:'Control Resonant Barrierefreiheit und Optionen', description:'Bestätigte und noch offene Angaben zu Barrierefreiheit, Untertiteln, Steuerung und Assistenzoptionen in Control Resonant.', label:'Zugänglichkeit', answer:'Für PS5 sind neun Funktionen bestätigt, darunter Mono-Audio, große Untertitel, vollständiges Controller-Remapping, Stick-Optionen, anpassbare Schwierigkeit und Pause. Eine plattformübergreifende Gesamtliste bleibt offen.', sections:[
    {heading:'Was bereits belegt ist',paragraphs:['Die PS5-Seite nennt Lautstärkeregelung, Mono-Audio, einfache und große Untertitel, vollständiges Controller-Remapping, Stick-Empfindlichkeit und -Invertierung, erweiterte Schwierigkeit sowie Pause. Steam listet außerdem Oberfläche und Untertitel in 15 Sprachen.','Nicht bestätigt sind damit automatisch Sprecherkennzeichnung, frei einstellbare Untertitel-Hintergründe, Farbenblind-Modi oder Screenreader. Plattformseiten können bis zum Start weitere Angaben erhalten.']},
    {heading:'Wichtige noch offene Funktionen',paragraphs:['Viele Spieler benötigen frei belegbare Tasten, Toggle-Optionen, anpassbare Zielhilfe, reduzierte Kameraeffekte oder Einstellungen für Kontrast und Farbenblindheit. Für Resonant ist bislang keine vollständige Matrix dieser Funktionen veröffentlicht.','Auch Motorik-, Seh- und Hörhilfen sollten nicht aus dem Vorgänger abgeleitet werden. Ein neues Kampfsystem und eine andere Benutzeroberfläche können Optionen verändern.']},
    {heading:'Kaufentscheidung vorbereiten',paragraphs:['Wer auf eine bestimmte Funktion angewiesen ist, sollte eine bestätigte Accessibility-Liste oder Tests der finalen Version abwarten. Wir aktualisieren diese Seite mit klaren Menüpfaden und Plattformunterschieden, sobald verlässliche Informationen vorliegen.']}
  ], sources:[{label:'Steam',url:steam},{label:'PlayStation Store',url:ps}] },
  { lang:'de', slug:'editionen-und-vorbestellung', englishPath:'/guides/editions-price-and-preorder/', title:'Control Resonant Editionen, Preis und Vorbestellung', description:'Standard- und Deluxe-Edition von Control Resonant, Vorbestellerinhalte, Early Access und offene Preisfragen.', label:'Kaufberatung', answer:'Control Resonant wird als Standard- und Digital-Deluxe-Angebot geführt. Auf PS5 umfasst die Deluxe Edition 48 Stunden Early Access. Preise und Inhalte können nach Plattform und Region variieren; prüfe deshalb den offiziellen Store vor dem Kauf.', sections:[
    {heading:'Standard oder Deluxe',paragraphs:['Die Standard Edition ist die richtige Referenz für das Grundspiel. Die digitale Deluxe Edition richtet sich an Käufer, die Zusatzinhalte und auf PS5 den früheren Zugang wünschen. Welche kosmetischen oder spielerischen Pakete enthalten sind, sollte direkt im regionalen Store verglichen werden.','Editionstabellen ändern sich gelegentlich vor Release. Wir vermeiden deshalb umgerechnete Preise aus fremden Regionen und nennen keine Händlerboni als allgemein gültig.']},
    {heading:'Vorbestellung und Early Access',paragraphs:['Der klar bestätigte zeitliche Vorteil ist der 48-Stunden-Zugang der PS5 Deluxe Edition ab 22. September 2026. Das ist kein genereller früher Release für alle Plattformen.','Vorbestellen ist für digitale Verfügbarkeit nicht nötig. Wer technische Tests, Reviews oder eine vollständige Accessibility-Liste abwarten möchte, verliert dadurch nicht den Zugang zum Grundspiel am regulären Termin.']},
    {heading:'Vor dem Bezahlen prüfen',paragraphs:['Kontrolliere Plattform, Kontoregion, enthaltene Inhalte, Rückgaberegeln und die ausgewiesene Startzeit. Drittanbieter-Keys können andere Regionen oder Aktivierungsbedingungen besitzen. Die sicherste Quelle für den konkreten Kauf ist der offizielle Plattform-Store.']}
  ], sources:[{label:'PlayStation Store',url:ps},{label:'Steam',url:steam}] },

  { lang:'fr', slug:'date-de-sortie', englishPath:'/release-date/', title:'Date de sortie de Control Resonant et accès anticipé', description:'Control Resonant sort le 24 septembre 2026. Dates confirmées, plateformes, accès anticipé PS5 et version Mac.', label:'Sortie', answer:'Control Resonant sortira mondialement le 24 septembre 2026 sur PS5, Xbox Series X|S et PC. Sur PS5, l’édition Digital Deluxe annonce 48 heures d’accès anticipé, dès le 22 septembre. Une version Mac est prévue plus tard en 2026.', sections:[
    {heading:'La date officielle',paragraphs:['Remedy Entertainment a confirmé le 24 septembre 2026 dans son annonce de lancement. Sur PC, le jeu sera disponible via Steam et Epic Games Store, avec une prise en charge de GeForce NOW annoncée dès la sortie.','La version macOS n’a pas encore de jour précis. Remedy indique seulement une arrivée plus tard en 2026. Les anciennes fenêtres générales et les dates de revendeurs ne doivent donc pas remplacer le calendrier officiel.']},
    {heading:'Accès anticipé et horaires',paragraphs:['La page PlayStation associe l’édition Digital Deluxe à un accès anticipé de 48 heures. Sur PS5, cela correspond au 22 septembre, sous réserve des conditions régionales affichées au moment de l’achat.','Les heures exactes de déblocage et de préchargement ne sont pas encore uniformément documentées. Elles peuvent dépendre de la plateforme et du fuseau horaire. Nous ajouterons ces détails lorsqu’ils seront publiés par Remedy ou les boutiques officielles.']},
    {heading:'Ce qui reste à confirmer',paragraphs:['La date Mac, les éventuelles éditions physiques et les horaires régionaux restent ouverts. Comme pour tout jeu avant sa sortie, le calendrier peut encore évoluer. Cette page distingue donc les annonces datées des simples suppositions.']}
  ], sources:sources([{label:'PlayStation Store',url:ps},{label:'Steam',url:steam}]) },
  { lang:'fr', slug:'configuration-pc', englishPath:'/guides/system-requirements/', title:'Configuration PC de Control Resonant : minimum et recommandée', description:'Configuration officielle de Control Resonant sur PC : processeur, carte graphique, RAM, stockage et Windows.', label:'Performance PC', answer:'Steam demande Windows 10/11 64 bits, 16 Go de RAM et 100 Go de stockage. Le minimum cite un Core i5-8500 ou équivalent AMD avec GTX 1070 ou RX 5600 XT 6 Go; la recommandation cite un Ryzen 7 3700X ou équivalent Intel avec RTX 3070 ou RX 6700 XT 8 Go.', sections:[
    {heading:'Configuration minimale',paragraphs:['La fiche Steam présente le niveau minimal comme une limite de compatibilité, sans préciser la résolution, le niveau graphique ni le nombre d’images par seconde visés. Elle associe un Intel Core i5-8500 ou un processeur AMD équivalent à 16 Go de mémoire vive.','Pour le GPU, les références sont la GeForce GTX 1070 et la Radeon RX 5600 XT avec 6 Go de mémoire vidéo. Il faut aussi un Windows 10 ou 11 en 64 bits et 100 Go d’espace libre.']},
    {heading:'Configuration recommandée',paragraphs:['Le profil recommandé monte vers un Ryzen 7 3700X ou un équivalent Intel. Côté graphique, Steam mentionne une RTX 3070 ou une RX 6700 XT avec 8 Go de VRAM. La RAM et le stockage restent fixés à 16 Go et 100 Go.','La fiche ne dit pas encore si ce profil suppose du ray tracing, une technologie d’upscaling ou de génération d’images. Il serait donc imprudent de promettre du 4K ou 60 fps à partir de cette seule liste.']},
    {heading:'Comparer avec son ordinateur',paragraphs:['Vérifiez d’abord la classe du GPU et la quantité de VRAM, puis le processeur et la mémoire. Les puces mobiles portant un nom proche des cartes de bureau peuvent offrir des performances différentes. Attendez les tests finaux avant un achat matériel coûteux.']}
  ], sources:[{label:'Steam – configuration officielle',url:steam}] },
  { lang:'fr', slug:'plateformes', englishPath:'/guides/platforms-and-performance/', title:'Plateformes de Control Resonant : PS5, Xbox, PC et Mac', description:'Toutes les plateformes confirmées pour Control Resonant, avec GeForce NOW, version Mac et informations de performance.', label:'Plateformes', answer:'Control Resonant est confirmé sur PS5, Xbox Series X|S et PC pour le 24 septembre 2026. GeForce NOW est annoncé au lancement. Une version Mac suivra plus tard en 2026; aucune version PS4, Xbox One ou Switch n’est annoncée.', sections:[
    {heading:'Les plateformes du lancement',paragraphs:['L’annonce officielle de Remedy nomme la PlayStation 5, les Xbox Series X|S et le PC via Steam et Epic Games Store. Le jeu vise donc la génération actuelle de consoles.','GeForce NOW doit permettre de diffuser la version PC dès la sortie. Ce service nécessite toutefois une licence compatible et un abonnement approprié; il ne constitue pas une édition autonome du jeu.']},
    {heading:'Mac et plateformes non annoncées',paragraphs:['La version macOS est prévue plus tard dans l’année 2026, sans date ni liste de Mac compatibles. Les exigences liées aux puces Apple et à la mémoire restent inconnues.','Aucune annonce officielle ne concerne PS4, Xbox One, Nintendo Switch ou une autre console Nintendo. Nous n’utilisons pas les fiches provisoires de revendeurs comme preuve de développement.']},
    {heading:'Modes graphiques et performances',paragraphs:['Remedy n’a pas encore détaillé tous les modes résolution et performance sur PS5, Series X et Series S. Les affirmations sur 60 fps, le ray tracing ou des compromis propres à la Series S doivent attendre une documentation technique ou des tests du jeu final.']}
  ], sources:sources([{label:'Steam',url:steam}]) },
  { lang:'fr', slug:'combat-et-builds', englishPath:'/guides/combat-and-build-systems-explained/', title:'Combat et builds de Control Resonant expliqués', description:'Comprendre le combat au corps à corps, l’arme Aberrant, les pouvoirs Instinct et le système de builds The Gap.', label:'Combat & builds', answer:'Control Resonant est un action-RPG centré sur le corps à corps. Dylan combine l’arme métamorphe Aberrant, des pouvoirs paranaturels appelés Instinct et le système de builds The Gap pour créer des styles de jeu distincts.', sections:[
    {heading:'Aberrant et le corps à corps',paragraphs:['Aberrant peut prendre plusieurs formes adaptées à des portées et à des situations différentes. Le placement, l’esquive et le changement de forme occupent donc une place plus importante que le tir continu du premier Control.','Dylan conserve une dimension paranaturelle grâce aux pouvoirs Instinct. Les présentations officielles montrent des enchaînements entre attaques, déplacements et capacités, mais les valeurs de dégâts restent susceptibles de changer avant la sortie.']},
    {heading:'Construire un build dans The Gap',paragraphs:['The Gap sert de centre à la progression et à la construction des builds. Le joueur y organise des éléments débloqués afin de faire interagir pouvoirs et modificateurs. Le deep dive officiel insiste sur la liberté de choix.','Une approche prudente consiste à choisir un objectif: contrôler les groupes, infliger de gros dégâts à une cible ou gagner en sécurité. Avant la version finale, aucun classement des meilleurs builds ne peut être vérifié.']},
    {heading:'Informations confirmées et conseils futurs',paragraphs:['Nous séparons les mécaniques annoncées des recommandations issues de tests. Après le lancement, chaque guide de build devra préciser sa version, ses prérequis et la méthode de vérification afin d’éviter les listes copiées ou devenues obsolètes.']}
  ], sources:[{label:'PlayStation Blog – combat',url:combat}] },
  { lang:'fr', slug:'new-game-plus', englishPath:'/guides/new-game-plus/', title:'New Game Plus de Control Resonant : détails confirmés', description:'Ce que Remedy a confirmé sur le New Game Plus de Control Resonant, la progression et les nouveaux défis.', label:'Modes de jeu', answer:'Le New Game Plus conserve les améliorations d’Aberrant, la santé, la ressource de combat, les capacités, talents et Artefacts. Les capacités de déplacement sont réinitialisées car elles restent liées au récit.', sections:[
    {heading:'Ce qui est officiel',paragraphs:['Remedy a consacré une présentation au New Game Plus avant même la sortie. Le mode doit renouveler la campagne après une première partie et proposer des rencontres ou variations supplémentaires.','Aberrant, santé, ressource des capacités de combat, capacités surnaturelles, talents et Artefacts sont conservés. Les pouvoirs de déplacement restent liés à la progression de l’histoire.']},
    {heading:'Progression et déblocage',paragraphs:['Un New Game Plus demande généralement de terminer l’histoire, mais la condition exacte de Resonant doit encore être documentée. On ignore également si plusieurs cycles successifs seront possibles.','Conserver une sauvegarde manuelle avant la fin peut être une précaution utile si le système le permet. Il ne s’agit toutefois pas d’une étape officiellement obligatoire.']},
    {heading:'L’intérêt pour les builds',paragraphs:['Un second parcours permet normalement d’utiliser plus longtemps un build abouti. La valeur du mode dépendra de la difficulté, des nouveaux ennemis et des modifications de progression. Nos conseils détaillés seront fondés sur la version commerciale, pas sur des suppositions.']}
  ], sources:[{label:'PlayStation Blog – New Game Plus',url:ngp}] },
  { lang:'fr', slug:'personnages-et-histoire', englishPath:'/guides/characters-and-story/', title:'Personnages et histoire de Control Resonant : Dylan Faden', description:'Présentation sans spoilers de Dylan Faden, Jesse, Manhattan et du point de départ de Control Resonant.', label:'Histoire', answer:'Dylan Faden est le protagoniste jouable de Control Resonant. Plusieurs années après Control, une crise paranaturelle déforme Manhattan. Jesse Faden reste liée à l’intrigue, mais Remedy présente le jeu comme une histoire autonome accessible aux nouveaux joueurs.', sections:[
    {heading:'Dylan devient protagoniste',paragraphs:['Dans le premier Control, Dylan était au cœur des expériences du Federal Bureau of Control et de la menace du Hiss. Resonant le place au premier plan pour explorer ses pouvoirs, son passé et sa relation avec Jesse.','Les textes officiels ne le décrivent pas comme un héros parfaitement stable. Son arme Aberrant et ses capacités difficiles à maîtriser portent à la fois le système de combat et son parcours personnel.']},
    {heading:'Une crise à Manhattan',paragraphs:['L’action dépasse désormais l’Oldest House. Manhattan est transformée par des phénomènes paranaturels et offre un espace plus vaste et plus connecté. Cette évolution ne suffit pas à définir le jeu comme un monde ouvert classique.','Remedy veut proposer un récit autonome. Les nouveaux venus doivent pouvoir comprendre l’objectif principal, tandis que les joueurs du premier épisode reconnaîtront davantage de liens.']},
    {heading:'Notre politique sur les spoilers',paragraphs:['Cette page s’en tient aux bandes-annonces et descriptions officielles. Le rôle précis de Jesse, la situation du FBC et l’identité des adversaires majeurs restent volontairement non détaillés. Les fuites ne sont pas présentées comme des faits.']}
  ], sources:sources([{label:'PlayStation Blog – histoire',url:story}]) },
  { lang:'fr', slug:'langues', englishPath:'/guides/language-support/', title:'Langues de Control Resonant : français, voix et sous-titres', description:'Langues officiellement prises en charge par Control Resonant, dont les voix françaises, l’interface et les sous-titres.', label:'Langues', answer:'Le français est entièrement pris en charge selon la matrice officielle de Steam: interface, voix intégrales et sous-titres. Quinze langues sont listées pour l’interface et les sous-titres; neuf disposent d’un doublage complet.', sections:[
    {heading:'Une version française complète',paragraphs:['Steam coche le français dans les trois catégories: interface, audio intégral et sous-titres. Le jeu devrait donc être entièrement jouable en français sur PC. Le traitement final des noms propres et de certains termes ne pourra être évalué qu’à la sortie.','La matrice linguistique peut encore être mise à jour avant le lancement. Pour une console ou une région particulière, vérifiez également la fiche locale de la boutique au moment de l’achat.']},
    {heading:'Les quinze langues affichées',paragraphs:['L’interface et les sous-titres sont annoncés en anglais, français, italien, allemand, espagnol d’Espagne, japonais, coréen, polonais, portugais du Brésil, russe, chinois simplifié, chinois traditionnel, ukrainien, espagnol d’Amérique latine et arabe.','Un doublage intégral est coché pour l’anglais, le français, l’italien, l’allemand, l’espagnol d’Espagne, le japonais, le portugais brésilien, le chinois simplifié et l’ukrainien. Les six autres langues sont actuellement listées sans voix complètes.']},
    {heading:'Différences entre boutiques',paragraphs:['La fiche Steam décrit la version PC. Les consoles peuvent télécharger des packs linguistiques ou appliquer des restrictions régionales différentes. La boutique correspondant à votre compte reste donc la référence finale.']}
  ], sources:[{label:'Steam – langues officielles',url:steam}] },
  { lang:'fr', slug:'monde-ouvert', englishPath:'/guides/is-control-resonant-open-world/', title:'Control Resonant est-il un monde ouvert ?', description:'Ce que signifie le Manhattan plus vaste de Control Resonant et pourquoi le jeu n’est pas simplement un open world classique.', label:'Exploration', answer:'Control Resonant se déroule dans un Manhattan plus vaste et connecté, mais Remedy ne le vend pas simplement comme un monde ouvert classique. La description la plus prudente est celle d’un action-RPG explorable, guidé par son récit et comportant des éléments de type Metroidvania.', sections:[
    {heading:'Un espace plus ouvert',paragraphs:['Resonant élargit nettement l’échelle par rapport aux secteurs fermés de l’Oldest House. Dylan peut explorer Manhattan, ouvrir des chemins et revenir dans certains lieux.','Cette liberté ne prouve pas l’existence d’une sandbox totale. Remedy conserve des missions mises en scène, des énigmes spatiales et une narration contrôlée. Une carte pleine d’icônes répétitives n’a pas été confirmée.']},
    {heading:'Exploration et nouvelles capacités',paragraphs:['Les pouvoirs acquis devraient modifier les possibilités de déplacement et d’accès. Les démonstrations montrent une ville plus interconnectée, sans encore détailler le voyage rapide, le nombre de quartiers ou toute la structure des activités secondaires.','La taille réelle ne peut pas être calculée à partir de bandes-annonces montées. Les distances, le rythme et la durée d’exploration devront être mesurés dans le jeu final.']},
    {heading:'À quoi faut-il s’attendre ?',paragraphs:['Les joueurs qui craignent un parcours strictement linéaire peuvent attendre davantage de liberté. Ceux qui recherchent une simulation urbaine sans limites doivent rester prudents. Après la sortie, nous vérifierons la carte, les retours en arrière et la liberté de mission.']}
  ], sources:sources([{label:'PlayStation Blog',url:story}]) },
  { lang:'fr', slug:'accessibilite', englishPath:'/guides/accessibility-options/', title:'Accessibilité de Control Resonant : options confirmées', description:'État des informations sur les sous-titres, commandes, aides et autres options d’accessibilité de Control Resonant.', label:'Accessibilité', answer:'Sur PS5, neuf fonctions sont confirmées: audio mono, grands sous-titres, remappage complet, réglages des sticks, difficulté ajustable et pause notamment. La matrice complète pour toutes les plateformes reste ouverte.', sections:[
    {heading:'Ce qui est déjà confirmé',paragraphs:['La fiche PS5 cite volume, audio mono, sous-titres simples et grands, remappage complet, sensibilité et inversion des sticks, difficulté avancée et pause. Steam indique en plus interface et sous-titres dans quinze langues.','Cela ne confirme pas automatiquement le nom des locuteurs, des fonds de sous-titres réglables, des filtres daltonisme ou un lecteur d’écran. Les autres plateformes doivent être vérifiées séparément.']},
    {heading:'Les options encore inconnues',paragraphs:['De nombreux joueurs ont besoin d’un remappage complet, de commandes à bascule, d’une aide à la visée, d’effets de caméra réduits ou de filtres de couleur. Aucun inventaire complet de ces réglages n’est disponible pour le moment.','Il ne faut pas copier automatiquement les options du premier Control. Le nouveau combat et la nouvelle interface peuvent modifier les besoins et les solutions proposées.']},
    {heading:'Conseil avant l’achat',paragraphs:['Si une fonction est indispensable, attendez une liste officielle ou un test fiable de la version commerciale. Nous ajouterons ensuite les chemins de menu, les limites et les différences entre PC, PS5 et Xbox.']}
  ], sources:[{label:'Steam',url:steam},{label:'PlayStation Store',url:ps}] },
  { lang:'fr', slug:'editions-et-precommande', englishPath:'/guides/editions-price-and-preorder/', title:'Éditions, prix et précommande de Control Resonant', description:'Comparer les éditions Standard et Digital Deluxe, l’accès anticipé, les bonus et les prix régionaux de Control Resonant.', label:'Guide d’achat', answer:'Control Resonant est proposé en édition Standard et en offre Digital Deluxe. Sur PS5, la Deluxe comprend 48 heures d’accès anticipé. Les prix et contenus peuvent varier selon la région et la plateforme: la boutique officielle locale doit être vérifiée avant paiement.', sections:[
    {heading:'Standard ou Digital Deluxe',paragraphs:['L’édition Standard sert de référence pour le jeu de base. La Digital Deluxe vise les joueurs intéressés par ses contenus supplémentaires et, sur PS5, par l’accès anticipé. Comparez la liste exacte dans votre boutique régionale.','Les tableaux d’édition évoluent parfois avant la sortie. Nous ne convertissons donc pas un prix étranger pour le présenter comme tarif français et nous ne généralisons pas les bonus d’un revendeur.']},
    {heading:'Précommande et accès anticipé',paragraphs:['L’avantage temporel clairement annoncé est l’accès de 48 heures de la Deluxe PS5, soit le 22 septembre 2026. Cette date avancée ne concerne pas automatiquement les autres plateformes.','Précommander n’est pas nécessaire pour garantir un exemplaire numérique. Attendre les tests techniques, les critiques ou la liste d’accessibilité peut être plus utile qu’un bonus incertain.']},
    {heading:'Vérifications essentielles',paragraphs:['Avant de payer, contrôlez la plateforme, la région du compte, les contenus, la politique de remboursement et l’heure affichée. Les clés tierces peuvent imposer une région ou des conditions d’activation différentes.']}
  ], sources:[{label:'PlayStation Store',url:ps},{label:'Steam',url:steam}] },

  { lang:'de', slug:'dylan-faden', englishPath:'/guides/dylan-faden/', title:'Dylan Faden in Control Resonant: Rolle und Fähigkeiten', description:'Wer Dylan Faden ist, warum er der einzige spielbare Charakter ist und welche bestätigte Rolle er in Control Resonant übernimmt.', label:'Charakter', answer:'Dylan Faden ist der einzige spielbare Charakter in Control Resonant. Nach Jahren in FBC-Gewahrsam wird er während der paranatürlichen Krise in Manhattan eingesetzt und sucht nach seiner vermissten Schwester Jesse.', sections:[
    {heading:'Vom Gefangenen zum Protagonisten',paragraphs:['Dylan wurde als Kind vom Federal Bureau of Control festgehalten und verbrachte einen großen Teil seines Lebens im Oldest House. Im ersten Control war er vom Hiss beeinflusst und wurde nach Jesses Eingreifen gereinigt, fiel danach jedoch in ein langes Koma.','Resonant beginnt mit einem erwachten Dylan, der eine für ihn fremde Welt verstehen muss. Remedy beschreibt ihn bewusst nicht als unkomplizierten Helden: Schuld, verlorene Selbstbestimmung und der Wunsch zu helfen bestimmen seinen Weg.']},
    {heading:'Spielbare Kräfte',paragraphs:['Dylan führt Aberrant, eine formwandelnde Nahkampfwaffe mit Primärformen, Sekundärformen und Combo-Endern. Seine übernatürlichen Kampffähigkeiten stammen aus Begegnungen mit mächtigen Resonants und werden über Talente und The Gap zu Builds kombiniert.','Offizielle Vorschauen zeigen außerdem Doppelsprung, zwei Luft-Dashes und kurzes Schweben. Die endgültigen Freischaltbedingungen und vollständigen Werte bleiben bis zur Veröffentlichung offen.']},
    {heading:'Beziehung zu Jesse',paragraphs:['Jesse ist verschwunden, bleibt aber der wichtigste persönliche Bezugspunkt. Dylan treibt die Handlung aktiv voran; Jesse prägt seinen Weg und ist nicht als zweiter spielbarer Charakter bestätigt. Diese Seite trennt bekannte Vorgeschichte von noch geheim gehaltenen Story-Ereignissen.']}
  ], sources:[{label:'PlayStation Blog – Story Trailer',url:story},{label:'PlayStation Blog – Kampf',url:combat}] },

  { lang:'de', slug:'jesse-faden', englishPath:'/guides/jesse-faden/', title:'Jesse Faden in Control Resonant: bestätigt, aber nicht spielbar', description:'Jesse Fadens bestätigte Rolle in Control Resonant, ihr Verschwinden und warum Dylan diesmal der einzige spielbare Charakter ist.', label:'Charakter', answer:'Jesse Faden bleibt zentral für die Geschichte von Control Resonant, ist aber nicht die spielbare Hauptfigur. Sie gilt zu Beginn als vermisst; Dylan sucht nach ihr und führt die Handlung als einziger spielbarer Charakter.', sections:[
    {heading:'Was offiziell feststeht',paragraphs:['Jesse ist die Direktorin des FBC und die Protagonistin des ersten Control. Remedy bestätigt ihre starke Präsenz im Nachfolger, hält aber Details ihrer neuen Reise bewusst zurück. Aus Trailern lässt sich deshalb weder ihr genauer Aufenthaltsort noch ihr Zustand sicher ableiten.','Die neue Rollenverteilung spiegelt die Geschwisterbeziehung: Im ersten Spiel ging Jesse ins Oldest House, nun geht Dylan hinaus nach Manhattan. Beide Geschichten drehen sich um die Fadens, aber Resonant gibt Dylan die aktive Perspektive.']},
    {heading:'Ist Jesse spielbar?',paragraphs:['Remedy bezeichnet Dylan ausdrücklich als einzigen spielbaren Charakter. Damit gibt es derzeit keinen Beleg für wechselnde Kampagnen, Koop mit Jesse oder ein separates Jesse-Kapitel. Eine Vision, Erinnerung oder Dialogszene wäre nicht automatisch ein spielbarer Abschnitt.','Wir ändern diese Einordnung nur bei einer neuen offiziellen Aussage oder nach Prüfung der veröffentlichten Version.']},
    {heading:'Spoilerfreie Abgrenzung',paragraphs:['Jesses Handlungen beeinflussen Dylans Reise, doch genaue Begegnungen, Wendungen und mögliche Enden gehören nicht in einen Vorab-Steckbrief. Unbestätigte Leaks und aus Trailerbildern abgeleitete Figurenlisten werden nicht übernommen.']}
  ], sources:[{label:'PlayStation Blog – Story und Charaktere',url:story}] },

  { lang:'de', slug:'zoe-de-vera', englishPath:'/guides/zoe-de-vera/', title:'Zoe De Vera in Control Resonant: Dylans FBC-Handlerin', description:'Zoe De Vera ist eine neue FBC-Feldagentin und Dylans Handlerin; hier stehen ihre bestätigte Funktion und Beziehung zu Dylan.', label:'Charakter', answer:'Zoe De Vera ist eine neue FBC-Feldagentin, die als Dylans Handlerin in Manhattan arbeitet. Ihre Beziehung basiert laut Remedy auf Vertrauen, Verantwortung und dem Lernen, sich auf andere zu verlassen.', sections:[
    {heading:'Bestätigte Funktion',paragraphs:['Zoe hat das Chaos außerhalb des Oldest House überlebt, während Dylan jahrelang isoliert war. Dadurch besitzt sie praktische Erfahrung mit der Lage in Manhattan und vermittelt zwischen ihm, dem FBC und der Außenwelt.','Remedy nennt die Beziehung einen emotionalen Anker der Geschichte. Das macht Zoe zu einer wichtigen Begleiterin, bestätigt sie aber weder als spielbaren Charakter noch als Koop-Partnerin.']},
    {heading:'Nahtlose Dialoge',paragraphs:['Control Resonant führt ein System ein, in dem Gespräche während der Erkundung weiterlaufen. Zoe kann dadurch Informationen und Charakterentwicklung liefern, ohne die Bewegung durch die Stadt ständig für Zwischensequenzen zu unterbrechen.','Welche Dialoge optional sind, ob Entscheidungen ihre Beziehung verändern und wie häufig sie physisch begleitet, ist noch nicht vollständig dokumentiert.']},
    {heading:'Keine erfundene Biografie',paragraphs:['Offizielle Quellen nennen noch keine ausführliche Vergangenheit, Dienstakte oder komplette Missionsliste von Zoe. Deshalb bleiben Alter, Herkunft und weitere Beziehungen offen, bis Remedy oder das Spiel selbst belastbare Angaben liefert.']}
  ], sources:[{label:'PlayStation Blog – Gameplay Deep Dive',url:combat}] },

  { lang:'de', slug:'demo-beta-und-playtest', englishPath:'/guides/demo-beta-and-playtest-status/', title:'Gibt es eine Control Resonant Demo, Beta oder einen Playtest?', description:'Aktueller Stand zur öffentlichen Control Resonant Demo, Beta und zum Playtest sowie die Abgrenzung von der 90-minütigen Medienvorschau.', label:'Demo & Verfügbarkeit', answer:'Bis zum 19. Juli 2026 ist keine öffentlich downloadbare Demo, Beta oder offene Testphase angekündigt. Die berichtete 90-minütige Demo war eine kontrollierte Medienvorschau und kein öffentlicher Download.', sections:[
    {heading:'Aktueller öffentlicher Status',paragraphs:['Remedys Release-Mitteilung sowie die offiziellen Steam- und PlayStation-Angebote nennen das Hauptspiel und Vorbestellungen, aber keinen öffentlichen Demo-Download und keinen Beta-Zeitplan. Das ist eine datierte Bestandsaufnahme, keine Aussage darüber, dass niemals eine Demo erscheinen kann.','Ein echter öffentlicher Test sollte über Remedy oder eine Plattformseite einen Zeitraum, unterstützte Systeme und eine offizielle Download-Schaltfläche nennen. Angebote über fremde Datei-Hosts sind kein verlässlicher Zugang.']},
    {heading:'Warum trotzdem von einer Demo die Rede ist',paragraphs:['Beim Summer Game Fest spielte PlayStation Blog ungefähr 90 Minuten einer Vorabversion. Der Bericht beschreibt den Spielbeginn, Bewegungsfähigkeiten, Nahkampf und einen großen Boss. Diese Sitzung liefert Gameplay-Informationen, war aber für eingeladene Medien bestimmt.','Auch der 48 Stunden frühere Zugang der PS5 Digital Deluxe Edition ist ein bezahlter Editionsvorteil und keine kostenlose Demo.']},
    {heading:'Wo Updates geprüft werden',paragraphs:['Maßgeblich sind Remedys News, die Steam-Seite und die Produktseiten von PlayStation und Xbox. Auf Steam wäre eine öffentliche Demo als eigener Download sichtbar. Wir aktualisieren den Status erst bei einer überprüfbaren offiziellen Änderung.']}
  ], sources:[{label:'Remedy – Veröffentlichung',url:remedy},{label:'Steam',url:steam},{label:'PlayStation Blog – Hands-on',url:handsOn}] },

  { lang:'de', slug:'medien-demo-hands-on', englishPath:'/guides/media-demo-hands-on-details/', title:'Control Resonant Medien-Demo: Details aus 90 Minuten Hands-on', description:'Die offizielle Medienvorschau zeigt Doppeldash, Doppelsprung, Schweben, Aberrant-Kombos und einen großen Boss im frühen Spiel.', label:'Gameplay-Vorschau', answer:'PlayStation Blog spielte auf dem Summer Game Fest rund 90 Minuten einer Vorabversion. Gezeigt wurden der Spielbeginn, Dylans Bewegungsset, Aberrant-Angriffe, paranatürliche Fähigkeiten und ein großer Boss.', sections:[
    {heading:'Inhalt der Sitzung',paragraphs:['Die Vorschau begann am Anfang des Spiels. Nach einem siebenjährigen Patt ist das Oldest House an den Hiss gefallen; verbliebene FBC-Agenten ziehen sich nach New York zurück. Dylan hilft beim Kampf und sucht Jesse.','Der Bericht beobachtete eine Kontaktaufnahme mit Jesse über eine offenbar nicht gewöhnliche räumliche Verbindung. Daraus lässt sich ihr tatsächlicher Aufenthaltsort jedoch nicht ableiten.']},
    {heading:'Steuerung und Bewegung',paragraphs:['Auf dem gezeigten PlayStation-Layout löste Kreis einen Dash aus, der vor der Landung zweimal möglich war. X aktivierte einen Doppelsprung; gehaltenes X erlaubte kurzes Schweben. Quadrat führte den Standardangriff aus, Dreieck die gewählte Sekundärform von Aberrant.','Drei paranatürliche Fähigkeiten lagen auf L1, R1 und R2. Belegung, Balance und Freischaltung können sich in der finalen Version unterscheiden.']},
    {heading:'Der unbenannte Boss',paragraphs:['Die Sitzung endete gegen einen riesigen Kopf aus Straßenschildern, Stahlträgern und Beton, der Teile warf und Trümmer schwang. Da der offizielle Bericht keinen Namen nennt, erzeugen wir keine erfundene Boss-Seite.']}
  ], sources:[{label:'PlayStation Blog – Summer Game Fest Hands-on',url:handsOn}] },

  { lang:'de', slug:'vorbesteller-boni', englishPath:'/guides/preorder-bonus-items/', title:'Control Resonant Vorbesteller-Boni: alle drei Gegenstände', description:'Bestätigt sind das Hiss-Corruption-Outfit, das Occult-Outfit und das Pickpocket’s-Tool-Artefakt; unbekannte Effekte bleiben offen.', label:'Gegenstände', answer:'Die offizielle PlayStation-Produktseite nennt drei Vorbesteller-Boni: Hiss Corruption Outfit, Occult Outfit und Pickpocket’s Tool Artifact. Für das Artefakt ist noch kein konkreter Effekt veröffentlicht.', sections:[
    {heading:'Die bestätigte Liste',paragraphs:['Die beiden Outfits sind nach Bezeichnung und Store-Kategorie kosmetische Inhalte. Pickpocket’s Tool wird ausdrücklich als Artefakt geführt und gehört damit zum passiven Ausrüstungssystem, das Überleben, Kampf, Erkundung oder Ressourcen beeinflussen kann.','Weder Modifier noch Bedingung, Nachteil oder späterer Fundort wurden beschrieben. Aussagen über mehr Geld, Beutechance oder Diebstahl wären reine Vermutung.']},
    {heading:'Nicht mit Deluxe-Inhalten verwechseln',paragraphs:['Digital Deluxe enthält zusätzlich AWE Mission Outfit, Untapped Artifact (Wallet), Starter Resource Bundle, Artbook und Soundtrack. Vorbestellbonus und Deluxe-Paket sind zwei getrennte Listen; ob beide gemeinsam gelten, muss die jeweilige regionale Produktseite ausdrücklich zeigen.','Preise, Fristen und Lieferbedingungen können sich je nach Plattform und Land unterscheiden.']},
    {heading:'Was noch offen bleibt',paragraphs:['Unbekannt ist, wann die Gegenstände im Spiel verfügbar werden, ob die Outfits Varianten besitzen und ob das Artefakt später regulär erhältlich ist. Diese Felder bleiben offen, statt aus Marketingnamen Funktionen abzuleiten.']}
  ], sources:[{label:'PlayStation Store – Standard Edition',url:psStore}] },

  { lang:'de', slug:'digital-deluxe-inhalte', englishPath:'/guides/digital-deluxe-items/', title:'Control Resonant Digital Deluxe: Inhalte und Gegenstände', description:'AWE Mission Outfit, Untapped Artifact Wallet, Starter-Ressourcenpaket, Artbook und Soundtrack der Digital Deluxe Edition erklärt.', label:'Editionen & Gegenstände', answer:'Digital Deluxe enthält das Hauptspiel, AWE Mission Outfit, Untapped Artifact (Wallet), Starter Resource Bundle, digitales Artbook und Original-Soundtrack. Auf PS5 sind außerdem 48 Stunden früherer Zugang beworben.', sections:[
    {heading:'Spielinhalte der Edition',paragraphs:['Das AWE Mission Outfit ist ein kosmetischer Gegenstand; der Name bedeutet nicht, dass eine zusätzliche Mission enthalten ist. Das Untapped Artifact (Wallet) gehört zur Rohform von Artefakten, die in The Gap zu nutzbarer passiver Ausrüstung verarbeitet werden.','Der Effekt des Wallet-Artefakts und die genaue Menge oder Art des Starter-Ressourcenpakets sind noch nicht veröffentlicht. Das Paket darf daher nicht als Level-Skip oder exklusive Fähigkeit beschrieben werden.']},
    {heading:'Digitale Extras',paragraphs:['Artbook und Original-Soundtrack sind digitale Medien. Offizielle Texte sagen nicht, dass die drei Gameplay-Gegenstände für Story, Builds oder New Game Plus benötigt werden.','Vorbesteller erhalten je nach Produktseite eine separate Gruppe aus zwei Outfits und einem Artefakt. Regionale Angebote sollten direkt vor dem Kauf verglichen werden.']},
    {heading:'Kaufprüfung',paragraphs:['Die US-PS5-Seite zeigte bei der letzten Prüfung 69,99 US-Dollar für Deluxe und 59,99 US-Dollar für Standard. Das sind keine garantierten Europreise. Entscheidend sind Konto-Region, Plattform, Rückgaberegeln und die lokal angezeigte Liste.']}
  ], sources:[{label:'PlayStation Store – Digital Deluxe',url:psDeluxe}] },

  { lang:'de', slug:'new-game-plus-uebernahme', englishPath:'/guides/new-game-plus-carryover-table/', title:'Control Resonant New Game Plus: Was wird übernommen?', description:'Aberrant-Upgrades, Gesundheit, Kampfähigkeit-Ressource, Fähigkeiten, Talente und Artefakte bleiben; Fortbewegungsfähigkeiten werden zurückgesetzt.', label:'New Game Plus', answer:'In New Game Plus bleiben Aberrant-Upgrades, Gesundheits- und Ressourcenverbesserungen, freigeschaltete Kampffähigkeiten, Talente und Artefakte erhalten. Storygebundene Fortbewegungsfähigkeiten werden nicht übernommen.', sections:[
    {heading:'Übernommener Fortschritt',paragraphs:['Remedy bestätigt sechs Bereiche: Aberrant-Upgrades, mehr Gesundheit, Verbesserungen der Combat-Ability-Ressource, freigeschaltete übernatürliche Kampffähigkeiten, Talente und Artefakte. Der zweite Lauf setzt den Kampfbau damit fort, statt alles zurückzusetzen.','Fortbewegungsfähigkeiten bleiben an die Story und die Entwicklung Manhattans gebunden. Die Quelle nennt noch nicht jede einzelne betroffene Bewegung, daher sollte nicht nur ein bestimmter Dash als Reset angenommen werden.']},
    {heading:'Neue Build-Möglichkeiten',paragraphs:['NG+ öffnet neue Talentknoten und erlaubt mehrere unterschiedliche Kampffähigkeiten desselben Bosses gleichzeitig. Dazu kommt ein vierter Artefakt-Slot; im ersten Lauf sind es höchstens drei.','Da im ersten Durchlauf nicht alles freigeschaltet werden kann, entstehen Kombinationen, die vorher unmöglich waren.']},
    {heading:'Veränderte Herausforderungen',paragraphs:['Gegner und Begegnungen entwickeln sich weiter, einige Bosse können neues Verhalten zeigen. Remedy nennt außerdem verpasste World Quests, Kopfgelder, Sammelobjekte sowie alternative Ausgänge bestimmter Nebenhandlungen als Gründe für eine Rückkehr.']}
  ], sources:[{label:'PlayStation Blog – New Game Plus',url:ngp}] },

  { lang:'de', slug:'ps5-barrierefreiheitsfunktionen', englishPath:'/guides/ps5-accessibility-feature-list/', title:'Control Resonant PS5: alle 9 Barrierefreiheitsfunktionen', description:'Die PS5-Seite nennt Lautstärke, Mono-Audio, Untertitel, große Untertitel, Remapping, Stick-Optionen, Schwierigkeit und Pause.', label:'Barrierefreiheit', answer:'Der PlayStation Store listet neun PS5-Funktionen: Lautstärkeregelung, Mono-Audio, einfache und große Untertitel, vollständiges Controller-Remapping, Stick-Empfindlichkeit, Stick-Invertierung, erweiterte Schwierigkeit und Spielpause.', sections:[
    {heading:'Audio und Untertitel',paragraphs:['Separate Lautstärken können reduziert oder stummgeschaltet werden; Mono-Audio gibt dasselbe Signal über jeden Lautsprecher aus. Neben einfachen Untertiteln ist eine größere Schriftgröße aufgeführt.','Die Store-Beschreibung nennt Untertitel für Hauptgeschichte und Hauptfiguren. Sie garantiert damit nicht automatisch Untertitel für jedes Umgebungsgeräusch oder jede optionale Hintergrundzeile.']},
    {heading:'Steuerung und Gameplay',paragraphs:['Das erweiterte Controller-Remapping wird als vollständige Anpassung der Steuerung beschrieben. Zusätzlich sind grundlegende Optionen für Stick-Empfindlichkeit und Richtungsumkehr vorhanden.','Die erweiterte Schwierigkeit erlaubt eine Anpassung des Herausforderungsgrads oder einzelne Hilfen. Im Offline-Spiel kann während Gameplay und Zwischensequenzen pausiert werden.']},
    {heading:'Geltungsbereich',paragraphs:['Die Liste ist direkt für die PS5-Seite belegt. PC und Xbox können vergleichbare Optionen besitzen, benötigen aber eine eigene Bestätigung. DualSense-Effekte und PS5-Pro-Optimierung sind separate Plattformmerkmale und zählen nicht zu den neun Accessibility-Einträgen.']}
  ], sources:[{label:'PlayStation Store – Accessibility',url:psStore}] },

  { lang:'fr', slug:'dylan-faden', englishPath:'/guides/dylan-faden/', title:'Dylan Faden dans Control Resonant : rôle et pouvoirs', description:'Qui est Dylan Faden, pourquoi il est le seul personnage jouable et quel rôle confirmé il tient dans Control Resonant.', label:'Personnage', answer:'Dylan Faden est le seul personnage jouable de Control Resonant. Après des années de détention par le FBC, il est déployé pendant la crise paranaturelle de Manhattan et recherche sa sœur Jesse.', sections:[
    {heading:'Du détenu au protagoniste',paragraphs:['Enlevé enfant par le Federal Bureau of Control, Dylan a vécu une grande partie de sa vie dans l’Oldest House. Dans le premier jeu, le Hiss l’a possédé; Jesse l’a purifié avant qu’il ne tombe dans un long coma.','Resonant le montre réveillé dans un monde qu’il connaît mal. Remedy ne le présente pas comme un héros simple: la culpabilité, la perte de contrôle et sa volonté d’aider structurent son parcours.']},
    {heading:'Arme et capacités',paragraphs:['Dylan manie Aberrant, une arme de mêlée métamorphe organisée en formes principales, formes secondaires et finisseurs de combo. Les grands boss Resonants accordent des capacités surnaturelles qui s’associent aux talents dans The Gap.','Les aperçus officiels montrent aussi deux dashs aériens, un double saut et une courte lévitation. Les conditions finales de déblocage restent inconnues.']},
    {heading:'Le lien avec Jesse',paragraphs:['Jesse a disparu mais demeure le point d’ancrage personnel de Dylan. Il fait avancer l’histoire comme protagoniste jouable; elle influence sa route sans être confirmée comme second personnage jouable.']}
  ], sources:[{label:'PlayStation Blog – histoire',url:story},{label:'PlayStation Blog – combat',url:combat}] },

  { lang:'fr', slug:'jesse-faden', englishPath:'/guides/jesse-faden/', title:'Jesse Faden dans Control Resonant : centrale, mais non jouable', description:'Le rôle confirmé de Jesse Faden, sa disparition et la raison pour laquelle Dylan est le seul personnage jouable de Control Resonant.', label:'Personnage', answer:'Jesse Faden reste centrale dans l’histoire, mais elle n’est pas la protagoniste jouable. Elle est portée disparue au début; Dylan la recherche et conduit l’aventure comme seul personnage jouable.', sections:[
    {heading:'Ce qui est confirmé',paragraphs:['Jesse dirige le FBC et était l’héroïne du premier Control. Remedy confirme sa présence importante dans la suite tout en gardant volontairement le silence sur son nouveau parcours. Son emplacement et son état ne peuvent pas être déduits avec certitude des bandes-annonces.','L’inversion est claire: Jesse entrait dans l’Oldest House, Dylan sort désormais vers Manhattan. Les deux récits concernent la destinée des Faden, mais la perspective active change.']},
    {heading:'Jesse est-elle jouable ?',paragraphs:['Remedy qualifie Dylan de seul personnage jouable. Aucune campagne alternée, coopération avec Jesse ou chapitre jouable séparé n’est donc confirmé. Une vision, un souvenir ou un dialogue ne constituerait pas automatiquement une section contrôlable.','Nous ne modifierons cette réponse qu’après une annonce officielle ou une vérification de la version finale.']},
    {heading:'Limiter les spoilers',paragraphs:['Les rencontres précises, retournements et fins possibles ne sont pas intégrés à cette fiche avant la sortie. Les fuites et listes de personnages déduites d’images sans légende restent exclues.']}
  ], sources:[{label:'PlayStation Blog – histoire et personnages',url:story}] },

  { lang:'fr', slug:'zoe-de-vera', englishPath:'/guides/zoe-de-vera/', title:'Zoe De Vera dans Control Resonant : agente et référente de Dylan', description:'Zoe De Vera est une nouvelle agente de terrain du FBC et la référente de Dylan; voici son rôle officiellement confirmé.', label:'Personnage', answer:'Zoe De Vera est une nouvelle agente de terrain du FBC qui sert de référente à Dylan dans Manhattan. Leur relation repose sur la confiance, la responsabilité et la capacité à compter sur autrui.', sections:[
    {heading:'Fonction confirmée',paragraphs:['Zoe a survécu au chaos extérieur pendant que Dylan restait isolé dans l’Oldest House. Elle possède donc une expérience concrète de Manhattan et relie Dylan, le Bureau et le monde extérieur.','Remedy décrit leur relation comme un pilier émotionnel. Cela ne confirme ni un personnage jouable, ni une partenaire de coopération.']},
    {heading:'Dialogues sans coupure',paragraphs:['Un nouveau système permet aux conversations de continuer pendant l’exploration. Zoe peut transmettre des informations et développer la relation sans interrompre constamment les déplacements par des cinématiques.','Les choix de dialogue, leurs conséquences et la fréquence de sa présence physique ne sont pas encore entièrement détaillés.']},
    {heading:'Biographie encore limitée',paragraphs:['Aucune source officielle ne donne pour l’instant son dossier complet, son âge ou toute sa liste de missions. Ces champs restent inconnus au lieu d’être complétés par des suppositions.']}
  ], sources:[{label:'PlayStation Blog – gameplay et personnages',url:combat}] },

  { lang:'fr', slug:'demo-beta-et-playtest', englishPath:'/guides/demo-beta-and-playtest-status/', title:'Existe-t-il une démo, bêta ou playtest de Control Resonant ?', description:'État de la démo publique, de la bêta et des tests de Control Resonant, avec distinction claire de la session presse de 90 minutes.', label:'Démo & disponibilité', answer:'Au 19 juillet 2026, aucune démo publique téléchargeable, bêta ouverte ou période de test n’est annoncée. La démo de 90 minutes évoquée dans la presse était une session média contrôlée.', sections:[
    {heading:'Situation actuelle',paragraphs:['Le communiqué de Remedy ainsi que les fiches Steam et PlayStation présentent le jeu complet et les précommandes, sans bouton de démo publique ni calendrier de bêta. Cette réponse est datée et pourra changer si une annonce officielle apparaît.','Un test public fiable doit indiquer ses plateformes, sa période et sa méthode de téléchargement sur un canal de Remedy ou une boutique reconnue. Les fichiers partagés ailleurs ne constituent pas une offre officielle.']},
    {heading:'La session appelée “démo”',paragraphs:['À Summer Game Fest, PlayStation Blog a joué environ 90 minutes d’une version de présentation. Le journaliste a vu le début, les mouvements de Dylan, le combat d’Aberrant et un grand boss. Cette expérience réservée aux médias confirme des mécaniques, pas un accès pour le public.','L’accès avancé de 48 heures de la Deluxe PS5 est également un avantage payant, pas une démo gratuite.']},
    {heading:'Où vérifier une annonce',paragraphs:['Les sources prioritaires sont les actualités Remedy et les boutiques Steam, PlayStation et Xbox. Une démo Steam publique aurait sa propre option de téléchargement. Le statut ne sera modifié qu’avec une preuve officielle vérifiable.']}
  ], sources:[{label:'Remedy – lancement',url:remedy},{label:'Steam',url:steam},{label:'PlayStation Blog – prise en main',url:handsOn}] },

  { lang:'fr', slug:'demo-presse-prise-en-main', englishPath:'/guides/media-demo-hands-on-details/', title:'Démo presse de Control Resonant : 90 minutes de prise en main', description:'La session officielle révèle double dash, double saut, lévitation, combos Aberrant et un grand boss au début du jeu.', label:'Aperçu gameplay', answer:'PlayStation Blog a joué environ 90 minutes à Summer Game Fest. La session couvrait le début du jeu, les déplacements de Dylan, les attaques d’Aberrant, des pouvoirs paranaturels et un grand boss.', sections:[
    {heading:'Contenu de la session',paragraphs:['La prise en main commençait au début de l’aventure. Après sept années d’impasse, l’Oldest House est tombée face au Hiss et les agents restants évacuent vers New York. Dylan accepte d’aider tout en cherchant Jesse.','Le journaliste a observé un contact avec Jesse semblant dépasser l’espace ordinaire, sans pouvoir établir son emplacement réel.']},
    {heading:'Commandes observées',paragraphs:['Sur la configuration PlayStation présentée, Cercle déclenchait un dash utilisable deux fois avant de toucher le sol. X permettait un double saut et, maintenu, une courte lévitation. Carré lançait l’attaque standard et Triangle la forme secondaire choisie.','Trois capacités paranaturelles utilisaient L1, R1 et R2. Les touches, l’équilibrage et la progression peuvent évoluer dans la version finale.']},
    {heading:'Boss sans nom officiel',paragraphs:['La session se terminait face à une énorme tête composée de panneaux, poutres et béton, capable de projeter des morceaux et de frapper avec les débris. La source ne donne aucun nom: nous ne créons donc pas une identité fictive.']}
  ], sources:[{label:'PlayStation Blog – Summer Game Fest',url:handsOn}] },

  { lang:'fr', slug:'bonus-de-precommande', englishPath:'/guides/preorder-bonus-items/', title:'Bonus de précommande de Control Resonant : les 3 objets', description:'Les tenues Hiss Corruption et Occult ainsi que l’artefact Pickpocket’s Tool sont confirmés; leurs effets inconnus ne sont pas inventés.', label:'Objets', answer:'La fiche PlayStation officielle cite trois bonus: Hiss Corruption Outfit, Occult Outfit et Pickpocket’s Tool Artifact. L’effet exact de cet artefact n’est pas encore publié.', sections:[
    {heading:'Liste confirmée',paragraphs:['Les deux tenues sont présentées comme des éléments cosmétiques. Pickpocket’s Tool est explicitement un Artefact et appartient donc au système d’équipement passif pouvant influencer survie, combat, exploration ou ressources.','Aucun modificateur, condition, compromis ou emplacement ultérieur n’est décrit. Lui attribuer un bonus de monnaie, de butin ou de vol serait spéculatif.']},
    {heading:'Différence avec la Deluxe',paragraphs:['La Digital Deluxe liste séparément AWE Mission Outfit, Untapped Artifact (Wallet), Starter Resource Bundle, artbook et bande originale. Bonus de précommande et contenus Deluxe sont donc deux ensembles distincts.','Le cumul, la date limite et la livraison doivent être vérifiés sur la fiche de la région et de la plateforme choisies.']},
    {heading:'Informations encore absentes',paragraphs:['On ignore quand les objets deviennent utilisables, si les tenues proposent des variantes et si l’artefact pourra être obtenu après le lancement. Ces champs restent ouverts jusqu’à une preuve officielle.']}
  ], sources:[{label:'PlayStation Store – édition Standard',url:psStore}] },

  { lang:'fr', slug:'contenu-digital-deluxe', englishPath:'/guides/digital-deluxe-items/', title:'Control Resonant Digital Deluxe : contenu et objets', description:'AWE Mission Outfit, Untapped Artifact Wallet, ressources de départ, artbook et bande originale de la Digital Deluxe expliqués.', label:'Éditions & objets', answer:'La Digital Deluxe contient le jeu, AWE Mission Outfit, Untapped Artifact (Wallet), Starter Resource Bundle, artbook numérique et bande originale. Sur PS5, elle annonce aussi 48 heures d’accès avancé.', sections:[
    {heading:'Objets liés au jeu',paragraphs:['AWE Mission Outfit est une tenue; son nom ne prouve pas la présence d’une mission supplémentaire. Untapped Artifact (Wallet) correspond à une forme non exploitée d’Artefact, transformable dans The Gap en équipement passif utilisable.','Son effet et le contenu quantitatif du pack de ressources ne sont pas publiés. Il ne faut donc pas les présenter comme un saut de niveau ou une capacité exclusive.']},
    {heading:'Bonus numériques',paragraphs:['L’artbook et la bande originale sont des médias numériques. Rien n’indique que les trois objets de gameplay soient nécessaires pour terminer l’histoire, accéder aux builds ou jouer au New Game Plus.','Les cadeaux de précommande constituent une autre liste et peuvent s’ajouter uniquement si la fiche régionale le précise.']},
    {heading:'Vérifications avant achat',paragraphs:['La fiche américaine PS5 affichait 69,99 dollars pour la Deluxe et 59,99 dollars pour la Standard lors de notre contrôle. Ces montants ne remplacent pas les tarifs locaux. Vérifiez région du compte, plateforme, remboursement et contenu exact.']}
  ], sources:[{label:'PlayStation Store – Digital Deluxe',url:psDeluxe}] },

  { lang:'fr', slug:'new-game-plus-transfert', englishPath:'/guides/new-game-plus-carryover-table/', title:'New Game Plus de Control Resonant : que conserve-t-on ?', description:'Améliorations d’Aberrant, santé, ressource, capacités, talents et Artefacts restent; les pouvoirs de déplacement repartent avec l’histoire.', label:'New Game Plus', answer:'Le New Game Plus conserve les améliorations d’Aberrant, de santé et de ressource, les capacités de combat débloquées, les talents et les Artefacts. Les capacités de déplacement liées au récit ne sont pas transférées.', sections:[
    {heading:'Progression transférée',paragraphs:['Remedy confirme six catégories conservées: Aberrant, santé, ressource des capacités de combat, capacités surnaturelles, talents et Artefacts. La seconde partie poursuit donc la construction du build.','Les pouvoirs de déplacement restent liés à la progression narrative et à l’évolution de Manhattan. La source ne nomme pas encore chaque mouvement concerné.']},
    {heading:'Nouvelles combinaisons',paragraphs:['Le mode ouvre de nouveaux nœuds de talent et permet d’équiper plusieurs capacités différentes provenant du même boss. Un quatrième emplacement d’Artefact s’ajoute aux trois de la première partie.','Comme tout ne peut pas être débloqué en un parcours, ces règles rendent possibles des synergies auparavant inaccessibles.']},
    {heading:'Défis et contenu rejoué',paragraphs:['Les ennemis et rencontres continuent d’évoluer; certains boss peuvent adopter de nouveaux comportements. Remedy invite aussi à reprendre quêtes du monde, contrats, collectibles et histoires secondaires dont certaines conversations ou issues peuvent changer.']}
  ], sources:[{label:'PlayStation Blog – New Game Plus',url:ngp}] },

  { lang:'fr', slug:'accessibilite-ps5-liste-complete', englishPath:'/guides/ps5-accessibility-feature-list/', title:'Control Resonant sur PS5 : les 9 fonctions d’accessibilité', description:'La fiche PS5 confirme volume, audio mono, sous-titres, grande taille, remappage, réglages des sticks, difficulté et pause.', label:'Accessibilité', answer:'Le PlayStation Store liste neuf fonctions PS5: volume, audio mono, sous-titres simples et grands, remappage complet, sensibilité et inversion des sticks, difficulté avancée et pause.', sections:[
    {heading:'Audio et sous-titres',paragraphs:['Les volumes individuels peuvent être réduits ou coupés; l’audio mono envoie le même signal à chaque haut-parleur. Les sous-titres disposent d’une option de grande taille.','La description mentionne les sous-titres pour l’histoire principale et les personnages principaux. Elle ne garantit pas automatiquement la transcription de chaque son ambiant ou ligne secondaire.']},
    {heading:'Commandes et gameplay',paragraphs:['Le remappage avancé est défini comme une personnalisation complète des commandes. La sensibilité et l’inversion des sticks disposent également d’options de base.','La difficulté avancée permet d’ajuster le défi ou d’activer séparément plusieurs aides. En jeu hors ligne, il est possible de mettre en pause gameplay et cinématiques.']},
    {heading:'Portée de la liste',paragraphs:['Ces neuf éléments sont vérifiés pour la fiche PS5. PC et Xbox peuvent proposer des options similaires, mais nécessitent leur propre confirmation. Les effets DualSense et l’amélioration PS5 Pro sont des fonctions de plateforme séparées.']}
  ], sources:[{label:'PlayStation Store – accessibilité',url:psStore}] },
];

export const localeHome = {
  de: { path:'/de/', title:'Control Resonant Guide auf Deutsch', description:'Deutscher Guide zu Control Resonant: Release, PC-Anforderungen, Plattformen, Kampf, Story, Sprachen und bestätigte Fakten.', label:'Inoffizieller deutscher Field Guide', heading:'CONTROL RESONANT', intro:'Der deutschsprachige Einstieg zu Remedys Action-RPG: geprüfte Informationen aus offiziellen Quellen, klare Hinweise auf noch offene Details und direkte Wege zu den wichtigsten Kauf- und Spielthemen.', guides:'Deutsche Guides', answer:'Control Resonant erscheint am 24. September 2026 für PS5, Xbox Series X|S und PC. Dylan Faden führt durch ein verzerrtes Manhattan; das Spiel setzt auf Nahkampf, Aberrant-Waffenformen, Instinct-Kräfte und anpassbare Builds.', sourceNote:'Alle Aussagen werden mit offiziellen Quellen belegt. Da das Spiel noch nicht erschienen ist, kennzeichnen wir offene Angaben und aktualisieren Seiten bei neuen Ankündigungen.' },
  fr: { path:'/fr/', title:'Guide français de Control Resonant', description:'Guide français de Control Resonant : sortie, configuration PC, plateformes, combat, histoire, langues et informations confirmées.', label:'Guide de terrain français non officiel', heading:'CONTROL RESONANT', intro:'Le point de départ francophone pour l’action-RPG de Remedy : des faits vérifiés dans les sources officielles, des limites clairement indiquées et un accès direct aux sujets essentiels avant l’achat.', guides:'Guides en français', answer:'Control Resonant sortira le 24 septembre 2026 sur PS5, Xbox Series X|S et PC. Dylan Faden explore un Manhattan déformé avec Aberrant, des pouvoirs Instinct et un système de builds orienté action au corps à corps.', sourceNote:'Chaque affirmation repose sur une source officielle. Le jeu n’étant pas encore disponible, nous signalons les informations manquantes et mettons les pages à jour après les annonces.' }
} as const;

export function pathFor(page: LocalizedPage, lang: Locale) {
  if (lang === 'en') return page.englishPath;
  const match = localizedPages.find((item) => item.englishPath === page.englishPath && item.lang === lang);
  return match ? `/${lang}/${match.slug}/` : `/${lang}/`;
}

export function alternatesFor(pathname: string) {
  if (pathname === '/' || pathname === '/de/' || pathname === '/fr/') return { en:'/', de:'/de/', fr:'/fr/' };
  if (pathname === '/database/' || pathname === '/de/datenbank/' || pathname === '/fr/base-de-donnees/') return { en:'/database/', de:'/de/datenbank/', fr:'/fr/base-de-donnees/' };
  const current = localizedPages.find((p) => p.englishPath === pathname || `/${p.lang}/${p.slug}/` === pathname);
  return current ? { en:current.englishPath, de:pathFor(current,'de'), fr:pathFor(current,'fr') } : null;
}
